-- ========================================
-- টেবিল / Table: fcm_tokens
-- তারিখ / Date: 2026-03-08 02:32:39
-- মোড / Mode: Full Export
-- মোট সারি / Total Rows: 16
-- ========================================

CREATE TABLE IF NOT EXISTS `fcm_tokens` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `user_id` int(11) DEFAULT NULL,
  `device_id` varchar(255) NOT NULL COMMENT 'unique browser/device',
  `token` varchar(255) NOT NULL,
  `token_last_updated_at` timestamp NULL DEFAULT NULL COMMENT 'Last time FCM token was created/refreshed (server trusted)',
  `topics` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL COMMENT 'Subscribed topics (JSON array of slugs)' CHECK (json_valid(`topics`)),
  `token_client_reported_at` bigint(20) DEFAULT NULL COMMENT 'Client-side reported timestamp (ms since epoch)',
  `permission` enum('granted','denied','default') DEFAULT 'default',
  `device_type` varchar(55) DEFAULT NULL,
  `device_name` varchar(100) DEFAULT NULL COMMENT 'Human readable device/browser name',
  `created_at` timestamp NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  `synced_at` timestamp NULL DEFAULT NULL COMMENT 'Last sync with Firebase',
  `revoked_at` timestamp NULL DEFAULT NULL COMMENT 'When token was revoked (logout/uninstall)',
  `last_notification_sent_at` datetime DEFAULT NULL,
  `last_notification_clicked_at` datetime DEFAULT NULL,
  `last_seen_at` datetime DEFAULT NULL,
  `token_status` varchar(32) DEFAULT 'active' COMMENT 'Token lifecycle state: active|revoked|expired|invalid (distinct from permission)',
  `failure_count` int(11) DEFAULT 0,
  `last_invalidated_at` datetime DEFAULT NULL,
  `token_hash` varchar(64) DEFAULT NULL COMMENT 'SHA256 hash of token for deduplication and backup searches',
  `last_used_at` datetime DEFAULT NULL COMMENT 'Last time token was successfully used for delivery',
  `delivery_count` int(11) DEFAULT 0 COMMENT 'Total successful deliveries via this token',
  PRIMARY KEY (`id`),
  UNIQUE KEY `unique_token_device` (`token`,`device_id`),
  UNIQUE KEY `uk_device_id` (`device_id`),
  UNIQUE KEY `uk_device_id_unique` (`device_id`),
  UNIQUE KEY `token_hash` (`token_hash`),
  KEY `user_id` (`user_id`),
  KEY `idx_fcm_tokens_last_seen` (`last_seen_at`),
  KEY `idx_permission_revoked` (`permission`,`revoked_at`),
  KEY `idx_token_status` (`token_status`),
  KEY `idx_user_device` (`user_id`,`device_id`),
  CONSTRAINT `fcm_tokens_ibfk_1` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=118 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

